// Получаем данные из входа (из Google Sheets)
const mentionsData = $input.all();

// Фильтруем пустые и собираем массив
const mentions = mentionsData
  .map(row => row.json.Handle)
  .filter(handle => handle && handle.trim() !== '')
  .filter(handle => handle.startsWith('@'));

// Делаем строку
const validMentionsString = mentions.join(', ');

// Возвращаем только новую переменную.
// Merge сам добавит это к основному потоку.
return [{
  json: {
    valid_mentions_string: validMentionsString,
    mentions_count: mentions.length
  }
}]

const item = $input.first();
const telegramText = $('Parse JSON Output').item.json.telegram_text || '';

// Находим все тикеры
const tickers = telegramText.match(/\$[A-Z]{2,6}/g) || [];

// Отслеживаем какие уже встречались
const seenTickers = new Set();
let result = telegramText;

tickers.forEach(ticker => {
  if (seenTickers.has(ticker)) {
    // Заменяем ВТОРОЕ и последующие упоминания на версию БЕЗ $
    const regex = new RegExp('\\' + ticker + '(?!\\w)', 'g');
    let count = 0;
    result = result.replace(regex, (match) => {
      count++;
      return count === 1 ? match : match.substring(1); // Первое оставляем, остальные без $
    });
  }
  seenTickers.add(ticker);
});

return [{
  json: {
    ...item.json,
    telegram_text: result
  }
}]

